const body = $input.first().json.body || $input.first().json || {};
const apiUrl = $env.N3_API_URL || '{{$env.GATEWAY_URL}}';
const secret = $env.N8N_INTERNAL_SECRET;
if (!secret) return [{ json: { error: true, message: 'N8N_INTERNAL_SECRET未設定', code: 'CONFIG_ERROR' } }];
const productId = body.product_id;
const sourceCountry = body.source_country || 'JP';
const destCountry = body.dest_country || 'US';
const destPlatform = body.dest_platform || 'ebay_us';
const targetProfitRate = parseFloat(body.target_profit_rate) || 0.20;
if (!productId) return [{ json: { error: true, message: 'product_id は必須', code: 'MISSING_PARAM' } }];
return [{ json: { product_id: productId, source_country: sourceCountry, dest_country: destCountry, dest_platform: destPlatform, target_profit_rate: targetProfitRate, api_url: apiUrl } }];

const config = $node['🔐 初期化'].json;
const productRaw = $node['📦 商品情報取得'].json;
const forwardersRaw = $node['🚚 代行会社取得'].json;
const settingsRaw = $node['⚙️ 設定取得'].json;
const product = Array.isArray(productRaw) ? productRaw[0] : productRaw;
if (!product || !product.id) return [{ json: { error: true, message: '商品が見つかりません' } }];
const forwarders = Array.isArray(forwardersRaw) ? forwardersRaw : (forwardersRaw ? [forwardersRaw] : []);
const settings = {};
const settingsArray = Array.isArray(settingsRaw) ? settingsRaw : [settingsRaw];
settingsArray.forEach(s => { if (s && s.setting_key) settings[s.setting_key] = parseFloat(s.setting_value) || s.setting_value; });

// 為替レート
const getRate = (from, to) => {
  if (from === to) return 1;
  const key = `exchange_rate_${from.toLowerCase()}_${to.toLowerCase()}`;
  return settings[key] || 150;
};

// VAT率
const vatRates = { 'DE': 0.19, 'FR': 0.20, 'UK': 0.20, 'IT': 0.22, 'ES': 0.21 };
const getVat = (country) => settings[`vat_rate_${country.toLowerCase()}`] || vatRates[country] || 0;

// プラットフォーム手数料
const platformFees = { 'ebay_us': 0.13, 'ebay_de': 0.12, 'amazon_us': 0.15, 'amazon_de': 0.15, 'shopify': 0.029, 'shopee': 0.10 };
const platformFee = platformFees[config.dest_platform] || 0.13;

const purchasePrice = parseFloat(product.purchase_price) || 0;
const sourceCurrency = config.source_country === 'JP' ? 'JPY' : (config.source_country === 'US' ? 'USD' : 'EUR');
const destCurrency = config.dest_country === 'JP' ? 'JPY' : (config.dest_country === 'US' ? 'USD' : (config.dest_country === 'UK' ? 'GBP' : 'EUR'));
const exchangeRate = getRate(sourceCurrency, destCurrency);
const vatRate = getVat(config.dest_country);

// 各代行会社でコスト計算
const routeCalculations = forwarders.map(fw => {
  const forwarderFee = parseFloat(fw.handling_fee) + parseFloat(fw.inspection_fee || 0);
  const shippingCost = parseFloat(fw.base_shipping) + (0.5 * parseFloat(fw.per_kg || 8));
  const dutyRate = 0.05;
  const purchaseDest = purchasePrice / exchangeRate;
  const forwarderFeeDest = forwarderFee / exchangeRate;
  const shippingDest = shippingCost / exchangeRate;
  const dutyAmount = purchaseDest * dutyRate;
  const subtotal = purchaseDest + forwarderFeeDest + shippingDest + dutyAmount;
  const vatAmount = subtotal * vatRate;
  const totalCost = subtotal + vatAmount;
  const salePrice = totalCost / (1 - platformFee - config.target_profit_rate);
  const netProfit = salePrice * (1 - platformFee) - totalCost;
  const actualMargin = salePrice > 0 ? netProfit / salePrice : 0;
  return {
    forwarder_id: fw.id,
    forwarder_name: fw.provider_name,
    forwarder_fee: Math.round(forwarderFeeDest * 100) / 100,
    shipping_cost: Math.round(shippingDest * 100) / 100,
    duty_amount: Math.round(dutyAmount * 100) / 100,
    vat_amount: Math.round(vatAmount * 100) / 100,
    total_cost: Math.round(totalCost * 100) / 100,
    calculated_price: Math.round(salePrice * 100) / 100,
    net_profit: Math.round(netProfit * 100) / 100,
    actual_margin: Math.round(actualMargin * 1000) / 10,
    lead_time_days: fw.lead_time_days || 10
  };
});

const optimal = routeCalculations.reduce((best, r) => r.net_profit > best.net_profit ? r : best, routeCalculations[0] || {});

return [{ json: { product_id: product.id, product_title: product.title || product.name, source_country: config.source_country, dest_country: config.dest_country, dest_platform: config.dest_platform, dest_currency: destCurrency, purchase_price: purchasePrice, purchase_currency: sourceCurrency, platform_fee_rate: platformFee, vat_rate: vatRate, route_calculations: routeCalculations, optimal_route: optimal } }];

const calcResult = $node['💰 ルート計算'].json;
const translateResult = $input.first().json;
const translatedTitle = translateResult.translated || translateResult.text || calcResult.product_title;
return [{ json: { ...calcResult, translated_title: translatedTitle } }];

const data = $node['📋 翻訳統合'].json;
const saveResult = $input.first().json;
return [{ json: { success: true, listing_id: saveResult?.id || null, product_id: data.product_id, optimal_route: data.optimal_route, translated_title: data.translated_title, calculated_price: data.optimal_route?.calculated_price, currency: data.dest_currency, all_routes: data.route_calculations } }];

// 🔐 HMAC SHA256 署名検証 (Empire OS v6)
const crypto = require('crypto');

const signature = $request.headers['x-n3-signature'] || $request.headers['X-N3-Signature'];
const timestamp = $request.headers['x-n3-timestamp'] || $request.headers['X-N3-Timestamp'];
const secret = $env.N8N_HMAC_SECRET;

if (!secret) {
  throw new Error('🚫 N8N_HMAC_SECRET 環境変数が未設定です');
}

if (!signature || !timestamp) {
  throw new Error('🚫 署名またはタイムスタンプが欠落しています');
}

// タイムスタンプ有効期限チェック (5分)
const now = Date.now();
const tsAge = now - parseInt(timestamp);
if (tsAge > 300000 || tsAge < -30000) {
  throw new Error('🚫 タイムスタンプが期限切れまたは不正です');
}

// HMAC検証
const bodyString = JSON.stringify($json);
const computedHmac = crypto
  .createHmac('sha256', secret)
  .update(timestamp + '.' + bodyString)
  .digest('hex');

if (signature !== computedHmac) {
  throw new Error('🚫 HMAC署名検証失敗: 不正なリクエスト');
}

// 検証成功 - 元データをそのまま返す
return [{ json: $json }];
